pages.css:
.page-02 {
  width: 1242px;
  height: 1660px;
  background-color: #FFFFFF;
  padding: 112px 100px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 80px;
}

.header-icon {
  font-size: 44px;
}

.header-label {
  font-size: 38px;
  color: #888888;
  font-weight: 500;
}

.hero-title-wrapper {
  margin-bottom: 80px;
}

.hero-title {
  display: flex;
  flex-direction: column;
  gap: 20px;
  margin: 0;
}

.hero-title span {
  font-size: 112px;
  font-weight: 600;
  color: #111111;
  line-height: 1.1;
}

.hero-title strong {
  font-size: 148px;
  font-weight: 900;
  color: #D92D20;
  line-height: 1.1;
}

.proof-list {
  display: flex;
  flex-direction: column;
  flex: 1;
  justify-content: center;
}

.proof-item {
  border-top: 2px solid #E5E5E5;
  padding: 48px 0;
  display: flex;
  gap: 48px;
  align-items: flex-start;
}

.proof-item:last-child {
  border-bottom: 2px solid #E5E5E5;
}

.proof-tag {
  flex-shrink: 0;
  width: 200px;
  font-size: 34px;
  font-weight: 600;
  color: #D92D20;
  background-color: #FFF2F1;
  border: 2px solid #FCDAD7;
  padding: 12px 0;
  border-radius: 12px;
  text-align: center;
  box-sizing: border-box;
}

.proof-text {
  flex: 1;
  font-size: 42px;
  line-height: 1.6;
  color: #222222;
  margin: 0;
  font-weight: 400;
}

.page-04 { width: 1242px; height: 1660px; background-color: #FAFAFA; box-sizing: border-box; padding: 100px 112px; display: flex; flex-direction: column; color: #111111; font-family: system-ui, -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Microsoft YaHei', sans-serif; letter-spacing: 0; }
.page-header { display: flex; align-items: center; font-size: 38px; color: #888888; margin-bottom: 60px; }
.page-header .label { font-weight: 600; margin-right: 16px; }
.page-title { font-size: 132px; font-weight: 900; line-height: 1.1; color: #111111; margin-bottom: 80px; }
.proof-list { display: flex; flex-direction: column; gap: 60px; flex: 1; }
.proof-item { display: flex; flex-direction: column; position: relative; padding-left: 40px; }
.proof-item::before { content: ''; position: absolute; left: 0; top: 12px; bottom: 12px; width: 6px; background-color: #DDDDDD; border-radius: 4px; }
.proof-tag { font-size: 46px; font-weight: 800; color: #111111; margin-bottom: 16px; }
.proof-text { font-size: 42px; line-height: 1.4; color: #444444; margin: 0; }
.highlight-item { margin-top: 20px; padding: 50px; background-color: #111111; border-radius: 16px; }
.highlight-item::before { display: none; }
.highlight-item .proof-tag { color: #FFFFFF; display: inline-block; background-color: #FF4D4F; padding: 8px 24px; border-radius: 8px; font-size: 40px; margin-bottom: 24px; }
.highlight-item .proof-text { color: #FFFFFF; font-size: 46px; font-weight: 600; line-height: 1.4; }

.page-05 {
  background-color: #F7F8FA;
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  padding: 100px 96px;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  display: flex;
  flex-direction: column;
  letter-spacing: 0;
}

.header {
  display: flex;
  flex-direction: column;
}

.label {
  font-size: 40px;
  color: #666;
  font-weight: 600;
}

.title {
  font-size: 132px;
  font-weight: 900;
  color: #111;
  margin-top: 24px;
  line-height: 1.1;
}

.sub-item {
  margin-top: 80px;
  padding: 40px 48px;
  border: 3px dashed #0052FF;
  background-color: #F0F5FF;
  border-radius: 16px;
  position: relative;
}

.sub-tag {
  position: absolute;
  top: -28px;
  left: 40px;
  background: #0052FF;
  color: #FFF;
  font-size: 36px;
  font-weight: 800;
  padding: 12px 24px;
  border-radius: 8px;
  line-height: 1;
}

.sub-text {
  font-size: 44px;
  color: #111;
  line-height: 1.6;
  font-weight: 600;
  margin: 0;
}

.steps-container {
  margin-top: 80px;
  display: flex;
  flex-direction: column;
  gap: 36px;
}

.step-item {
  display: flex;
  align-items: center;
  gap: 36px;
  background: #FFFFFF;
  padding: 48px 40px;
  border-radius: 16px;
  box-shadow: 0 12px 32px rgba(0, 0, 0, 0.03);
}

.step-num {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 64px;
  font-weight: 900;
  color: #0052FF;
  line-height: 1;
  flex-shrink: 0;
  background: #F0F5FF;
  padding: 16px 20px;
  border-radius: 12px;
}

.step-content {
  flex-grow: 1;
}

.step-text {
  font-size: 42px;
  color: #444;
  line-height: 1.6;
  margin: 0;
}

.step-text strong {
  color: #111;
  font-size: 44px;
  font-weight: 800;
}

.page-06 {
  width: 1242px;
  height: 1660px;
  background-color: #FFFFFF;
  box-sizing: border-box;
  padding: 112px 100px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 100px;
}

.header-icon {
  font-size: 44px;
}

.header-label {
  font-size: 40px;
  color: #888888;
  font-weight: 600;
}

.content {
  display: flex;
  flex-direction: column;
  flex: 1;
}

.page-title {
  font-size: 132px;
  font-weight: 900;
  color: #111111;
  line-height: 1.1;
  margin-bottom: 140px;
}

.cta-list {
  display: flex;
  flex-direction: column;
  gap: 72px;
}

.cta-item {
  display: flex;
  flex-direction: column;
  padding-bottom: 72px;
  border-bottom: 2px solid #F0F0F0;
}

.cta-item:last-child {
  border-bottom: none;
  padding-bottom: 0;
}

.cta-tag {
  font-size: 40px;
  font-weight: 800;
  color: #111111;
  margin-bottom: 24px;
  display: flex;
  align-items: center;
}

.cta-tag::before {
  content: "";
  display: inline-block;
  width: 12px;
  height: 40px;
  background-color: #0052FF;
  margin-right: 20px;
  border-radius: 6px;
}

.cta-text {
  font-size: 44px;
  color: #555555;
  line-height: 1.6;
  margin: 0;
}
